class StreamChecker:
    def __init__(self, words):
        self.words = set(words)
        self.maxlen = max(len(w) for w in words)
        self.stream = []
    def query(self, letter):
        self.stream.append(letter)
        if len(self.stream) > self.maxlen:
            self.stream.pop(0)
        s = ''.join(self.stream)
        for i in range(len(s)):
            if s[i:] in self.words:
                return True
        return False

