class StreamChecker:
    def __init__(self, words):
        self.trie = {}
        self.maxlen = 0
        for w in words:
            self.maxlen = max(self.maxlen, len(w))
            node = self.trie
            for ch in reversed(w):
                node = node.setdefault(ch, {})
            node['$'] = True
        self.stream = []
    def query(self, letter):
        self.stream.append(letter)
        if len(self.stream) > self.maxlen:
            self.stream.pop(0)
        node = self.trie
        for ch in reversed(self.stream):
            if ch not in node:
                return False
            node = node[ch]
            if '$' in node:
                return True
        return False

